/**
 * CLI: read ecology graph snapshot JSON from stdin or file, exit 0 iff validate passes.
 * Usage: pnpm exec tsx ./scripts/validate-ecology-snapshot.ts [path/to/snapshot.json]
 */
import * as fs from 'node:fs';
import { validateEcologyGraphSnapshot } from '../src/ecology-graph-snapshot';

function main(): void {
  const path = process.argv[2];
  const raw =
    path === undefined || path === '-'
      ? fs.readFileSync(0, 'utf8')
      : fs.readFileSync(path, 'utf8');
  let json: unknown;
  try {
    json = JSON.parse(raw) as unknown;
  } catch {
    process.stderr.write('ecology-snapshot: invalid JSON\n');
    process.exit(1);
  }
  const r = validateEcologyGraphSnapshot(json);
  if (!r.ok) {
    process.stderr.write(`ecology-snapshot: ${r.reason}\n`);
    process.exit(1);
  }
  process.stdout.write('ecology-snapshot: ok\n');
  process.exit(0);
}

main();
